        handleTaskUpdated(updatedTask) {
            console.log('Task updated in Gantt chart componet', updatedTask);
            const taskIndex = this.tasks.findIndex(task => task.id === updatedTask.id);
            if (taskIndex !== -1) {
                this.tasks[taskIndex].start = new Date(updatedTask.startTime);
                this.tasks[taskIndex].end = new Date(updatedTask.endTime);
                this.tasks[taskIndex].duration = updatedTask.duration;
                const dragTypeMessages = {
